import { useState, useEffect } from "react";
import axios from "axios";
import "./../styles/Library.css";

const API_BASE = "http://localhost:5000/books";

export default function LibraryApp() {
  const [books, setBooks] = useState([]);
  const [borrowedBooks, setBorrowedBooks] = useState([]);
  const [title, setTitle] = useState("");
  const [author, setAuthor] = useState("");
  const [description, setDescription] = useState("");
  const [publishedYear, setPublishedYear] = useState("");

  useEffect(() => {
    fetchBooks();
    fetchBorrowedBooks();
  }, []);

  const fetchBooks = async () => {
    try {
      const response = await axios.get(API_BASE);
      setBooks(response.data.books);
    } catch (error) {
      console.error("Error fetching books", error);
    }
  };

  const fetchBorrowedBooks = async () => {
    try {
      const response = await axios.get(`${API_BASE}/borrowed`, {
        headers: { Authorization: `Bearer ${localStorage.getItem("token")}` },
      });
      setBorrowedBooks(response.data.books);
    } catch (error) {
      console.error("Error fetching borrowed books", error);
    }
  };

  const addBook = async () => {
    try {
      const response = await axios.post(
        `${API_BASE}/add`,
        { title, author, description, published_year: publishedYear },
        { headers: { Authorization: `Bearer ${localStorage.getItem("token")}` } }
      );
      setBooks([...books, response.data.book]);
      setTitle("");
      setAuthor("");
      setDescription("");
      setPublishedYear("");
    } catch (error) {
      console.error("Error adding book", error);
    }
  };

  const borrowBook = async (bookId) => {
    try {
      await axios.post(
        `${API_BASE}/borrow`,
        { book_id: bookId },
        { headers: { Authorization: `Bearer ${localStorage.getItem("token")}` } }
      );
      fetchBorrowedBooks();
    } catch (error) {
      console.error("Error borrowing book", error);
    }
  };

  const returnBook = async (bookId) => {
    try {
      await axios.put(
        `${API_BASE}/return/${bookId}`,
        {},
        { headers: { Authorization: `Bearer ${localStorage.getItem("token")}` } }
      );
      fetchBorrowedBooks();
    } catch (error) {
      console.error("Error returning book", error);
    }
  };

  return (
    <div className="library-container">
      <h1 className="library-title">Library Management</h1>

      <div className="book-form">
        <input
          className="library-input"
          placeholder="Title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
        />
        <input
          className="library-input"
          placeholder="Author"
          value={author}
          onChange={(e) => setAuthor(e.target.value)}
        />
        <input
          className="library-input"
          placeholder="Description"
          value={description}
          onChange={(e) => setDescription(e.target.value)}
        />
        <input
          className="library-input"
          placeholder="Published Year"
          value={publishedYear}
          onChange={(e) => setPublishedYear(e.target.value)}
        />
        <button className="library-button" onClick={addBook}>Add Book</button>
      </div>

      <h2 className="library-subtitle">Available Books</h2>
      <ul className="book-list">
        {books.map((book) => (
          <li key={book.id} className="book-item">
            {book.title} by {book.author}
            <button className="borrow-button" onClick={() => borrowBook(book.id)}>Borrow</button>
          </li>
        ))}
      </ul>

      <h2 className="library-subtitle">Borrowed Books</h2>
      <ul className="book-list">
        {borrowedBooks.map((book) => (
          <li key={book.id} className="book-item">
            {book.title} by {book.author}
            <button className="return-button" onClick={() => returnBook(book.id)}>Return</button>
          </li>
        ))}
      </ul>
    </div>
  );
}
